import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.CylwKCfq.js";const g=JSON.parse('{"title":"🌐 Try the Live Demo","description":"","frontmatter":{},"headers":[],"relativePath":"guide/layer1-product.md","filePath":"guide/layer1-product.md"}'),n={name:"guide/layer1-product.md"};function i(s,e,d,l,h,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🌐-try-the-live-demo" tabindex="-1">🌐 Try the Live Demo <a class="header-anchor" href="#🌐-try-the-live-demo" aria-label="Permalink to &quot;🌐 Try the Live Demo&quot;">​</a></h1><p>The fastest way to trace blockchain transactions — no setup, no API key, no code.</p><h2 id="open-the-demo" tabindex="-1">Open the Demo <a class="header-anchor" href="#open-the-demo" aria-label="Permalink to &quot;Open the Demo&quot;">​</a></h2><p>Go to the <a href="/txgraph/demo/" target="_self">Live Demo</a> page to start tracing immediately. The demo supports two data source modes:</p><ul><li><strong>TrustIn</strong> — uses the TrustIn API with risk scoring and entity tagging</li><li><strong>On-Chain</strong> — fetches raw data directly from Etherscan (Ethereum) or Tronscan (Tron)</li></ul><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><ol><li>Open the <a href="/txgraph/demo/" target="_self">Live Demo</a></li><li>Enter a blockchain address (Ethereum or Tron)</li><li>Select data source: <strong>TrustIn</strong> or <strong>On-Chain</strong></li><li>Select direction: <strong>Inflow</strong> / <strong>Outflow</strong> / <strong>All</strong></li><li>Click <strong>Explore</strong> — the graph loads instantly</li></ol><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><h3 id="risk-levels" tabindex="-1">Risk Levels <a class="header-anchor" href="#risk-levels" aria-label="Permalink to &quot;Risk Levels&quot;">​</a></h3><p>Each node (address) is colored by risk:</p><table tabindex="0"><thead><tr><th>Color</th><th>Risk Level</th><th>Meaning</th></tr></thead><tbody><tr><td>🔴 Red</td><td>High</td><td>Sanctioned, dark market, mixer</td></tr><tr><td>🟡 Yellow</td><td>Medium</td><td>Suspicious patterns detected</td></tr><tr><td>🟢 Green</td><td>Low</td><td>Verified exchange, known entity</td></tr><tr><td>⚫ Gray</td><td>Unknown</td><td>No data available</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Risk scoring and entity tags are only available when using the <strong>TrustIn</strong> data source. On-Chain mode shows all nodes as &quot;unknown&quot; risk.</p></div><h3 id="expanding-the-graph" tabindex="-1">Expanding the Graph <a class="header-anchor" href="#expanding-the-graph" aria-label="Permalink to &quot;Expanding the Graph&quot;">​</a></h3><ul><li>Click any node to see its details</li><li>Click the <strong>+</strong> button on a node to expand its connections</li><li>Right-click a node to remove it from the view</li></ul><h3 id="renderer-modes" tabindex="-1">Renderer Modes <a class="header-anchor" href="#renderer-modes" aria-label="Permalink to &quot;Renderer Modes&quot;">​</a></h3><p>Switch between two renderers:</p><ul><li><strong>ReactFlow</strong> — best for interactive exploration, drag nodes, zoom</li><li><strong>Sigma.js</strong> — best for large graphs (1000+ nodes), WebGL-accelerated</li></ul><h2 id="when-to-use-the-demo" tabindex="-1">When to use the Demo <a class="header-anchor" href="#when-to-use-the-demo" aria-label="Permalink to &quot;When to use the Demo&quot;">​</a></h2><p>✅ Quick investigation — need an answer now ✅ No technical setup required ✅ Compare TrustIn vs on-chain data ✅ Regular compliance checks</p><p>→ For programmatic access, see <a href="/txgraph/guide/layer2-agent.html">Layer 2: AI Agent API</a>. To run locally, see <a href="/txgraph/guide/layer3-demo.html">Layer 3: Local Demo</a>. To embed in your own app, see <a href="/txgraph/guide/layer4-component.html">Layer 4: Build Your Own</a>.</p>',20)])])}const p=t(n,[["render",i]]);export{g as __pageData,p as default};
